**Problem:** Unhandled errors bubble up to Express's default handler, which may expose stack traces in responses.

**Fix:** Add a global error handler as the **last** middleware:

```js
// ✅ Global error handler — must have 4 params
app.use((err, req, res, next) => {
  console.error({ message: err.message, stack: err.stack, path: req.path });
  res.status(err.status ?? 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'  // never leak stack traces
      : err.message,
  });
});
```

---

### 🟡 8. No Request Logging / Audit Trail (A09 – Logging & Monitoring)

**Problem:** There is no logging of requests, errors, or access events. This makes incident detection and forensics impossible.

**Fix:** Add `morgan` for HTTP access logs and a structured logger (e.g., `pino`) for application events:

```bash
npm install morgan pino pino-http
```

```js
const morgan = require('morgan');

// ✅ HTTP access log — use 'combined' format in production
app.use(morgan(process.env.NODE_ENV === 'production' ? 'combined' : 'dev'));
```

---

### 🟢 9. Hard-Coded Port (A05 – Security Misconfiguration)

**Problem:** Port `3000` is hard-coded, making environment-specific configuration impossible.

```js
// ❌ CURRENT
app.listen(3000, () => { ... });
```

**Fix:**
```js
// ✅ FIXED
const PORT = parseInt(process.env.PORT ?? '3000', 10);
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

## Recommended Dependency List

```bash
npm install helmet cors express-rate-limit express-validator morgan jsonwebtoken
npm install --save-dev nodemon
```

---

## Hardened `app.js` — Putting It All Together

```js
'use strict';

const express  = require('express');
const helmet   = require('helmet');
const cors     = require('cors');
const morgan   = require('morgan');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');
const jwt      = require('jsonwebtoken');

const app = express();

// ── Security middleware (order matters) ──────────────────────────────────────
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],
  allowedHeaders: ['Authorization'],
}));
app.use(express.json({ limit: '10kb' }));
app.use(morgan(process.env.NODE_ENV === 'production' ? 'combined' : 'dev'));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));

// ── Auth middleware ───────────────────────────────────────────────────────────
function requireAuth(req, res, next) {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
}

// ── Routes ────────────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => {
  const isAdmin = req.user?.role === 'admin';
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'   },
  ];
  res.json(users.map(u => ({
    id:    u.id,
    name:  u.name,
    email: isAdmin ? u.email : `${u.email[0]}***@${u.email.split('@')[1]}`,
  })));
});

// ── Global error handler (must be last) ───────────────────────────────────────
app.use((err, req, res, _next) => {
  console.error({ path: req.path, error: err.message });
  res.status(err.status ?? 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message,
  });
});

const PORT = parseInt(process.env.PORT ?? '3000', 10);
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

module.exports = app;
```

---

## Priority Action Plan

1. **Immediately:** Add authentication to `/users` — this is the most critical gap.
2. **Before next deploy:** Install and configure `helmet`, `cors`, and `express-rate-limit`.
3. **This sprint:** Add error handling middleware and request logging.
4. **Ongoing:** Enforce input validation on every route that accepts user data; run `npm audit` in CI.

